// Processa TODOS os itens do webhook
const items = $input.all();

// Função para garantir +55 no telefone
function formatPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.toString().trim().replace(/\D/g, ''); // Remove tudo que não é número

  // Se já tem 55 no início, mantém
  if (cleaned.startsWith('55')) {
    return `+${cleaned}`;
  }

  // Se não tem 55, adiciona +55
  return `+55${cleaned}`;
}

// Função para identificar navio e estilo
function identificarNavioEstilo(utmCampaign, utmContent, utmTerm) {
  const texto = `${utmCampaign} ${utmContent} ${utmTerm}`.toLowerCase();

  const navios = [
    { keywords: ['gusttavo', 'gustavo', 'embaixador'], navio: 'NAVIO DO EMBAIXADOR', estilo: 'SERTANEJO' },
    { keywords: ['leonardo', 'cabare', 'cabaré'], navio: 'NAVIO CABARÉ', estilo: 'SERTANEJO' },
    { keywords: ['chitaozinho', 'chitãozinho', 'xororo', 'xororó', 'ch&x', 'chx'], navio: 'NAVIO CH&X', estilo: 'SERTANEJO' },
    { keywords: ['joao-gomes', 'joão-gomes', 'dominguinho'], navio: 'NAVIO DOMINGUINHO EM ALTO MAR', estilo: 'FORRÓ' },
    { keywords: ['reveillon', 'réveillon', 'ano-novo'], navio: 'NAVIO REVEILLON EM ALTO MAR', estilo: 'VARIADO' },
    { keywords: ['bell-marques', 'vumbora'], navio: 'NAVIO VUMBORA PRO MAR', estilo: 'AXÉ/FORRÓ' },
    { keywords: ['89-rock', '89rock', 'rock-boat'], navio: 'NAVIO 89 ROCK BOAT', estilo: 'ROCK' }
  ];

  for (const config of navios) {
    if (config.keywords.some(kw => texto.includes(kw))) {
      return { navio: config.navio, estilo: config.estilo };
    }
  }

  return { navio: 'NÃO IDENTIFICADO', estilo: 'NÃO IDENTIFICADO' };
}

// Processa cada item
return items.map(inputItem => {
  const item = inputItem.json.body;

  // Processa telefone - tenta várias fontes
  let telefone = '';

  // 1. Tenta pegar do campo telefone direto
  if (item.telefone) {
    telefone = item.telefone;
  }
  // 2. Tenta pegar do campo com nome longo (Pluga)
  else if (item['Qual seu whatsapp? Enviaremos um Orçamento por lá']) {
    const campoWhats = item['Qual seu whatsapp? Enviaremos um Orçamento por lá'];
    if (typeof campoWhats === 'object' && campoWhats['\t']) {
      telefone = campoWhats['\t'];
    } else if (typeof campoWhats === 'string') {
      telefone = campoWhats;
    }
  }

  telefone = formatPhone(telefone);

  // Identifica navio e estilo
  const { navio, estilo } = identificarNavioEstilo(
    item.utm_campaign || '',
    item.utm_content || '',
    item.utm_term || ''
  );

  // Extrai quantidade de pessoas
  let quantasPessoas = item.cabine_pessoas || item.quantas_pessoas || '';
  if (quantasPessoas && typeof quantasPessoas === 'string') {
    const match = quantasPessoas.match(/(\d+)/);
    quantasPessoas = match ? match[1] : quantasPessoas;
  }

  // Retorna o objeto processado
  return {
    json: {
      nome: item.nome || '',
      telefone: telefone,
      email: item.email || '',
      quantas_pessoas: quantasPessoas,

      // Estrutura correta do Meta Ads
      campanha: item.utm_campaign || '',
      conjunto_de_anuncio: item.utm_content || '',
      anuncio: item.utm_term || '',

      // Navio e estilo identificados
      navio_interessado: navio,
      estilo: estilo,

      // Dados extras
      tipo_cabine: item['Qual tipo de experience resource você deseja?'] || '',
      ja_fez_cruzeiro: item['Já fez um cruzeiro?'] || '',
      utm_source: item.utm_source || ''
    }
  };
});
